diff --git a/src/njs_vmcode.c b/src/njs_vmcode.c
index ec47865..98bcbde 100644
--- a/src/njs_vmcode.c
+++ b/src/njs_vmcode.c
@@ -797,8 +797,20 @@ next:
                 pnext = (njs_vmcode_prop_next_t *) pc;
                 retval = njs_scope_value(vm, pnext->retval);

+                if (njs_slow_path(value2->type != NJS_DATA
+                                  || value2->data.magic32 != NJS_DATA_TAG_ARRAY_ITERATOR))
+                {
+                    njs_internal_error(vm, "invalid iterator state");
+                    goto error;
+                }
+
                 next = value2->data.u.next;

+                if (njs_slow_path(next == NULL || next->array == NULL)) {
+                    njs_internal_error(vm, "iterator is invalid");
+                    goto error;
+                }
+
                 if (next->index < next->array->length) {
                     *retval = next->array->start[next->index++];

@@ -1430,7 +1442,7 @@ njs_vmcode_property_foreach(njs_vm_t *vm, njs_value_t *object,
         return NJS_ERROR;
     }

-    vm->retval.data.u.next = next;
+    njs_set_data(&vm->retval, next, NJS_DATA_TAG_ARRAY_ITERATOR);

     code = (njs_vmcode_prop_foreach_t *) pc;

diff --git a/src/class.c b/src/class.c
