 }

diff --git a/src/njs_vmcode.c b/src/njs_vmcode.c
index ef0beb5..d2543c6 100644
--- a/src/njs_vmcode.c
+++ b/src/njs_vmcode.c
@@ -1055,18 +1055,22 @@ njs_vmcode_array(njs_vm_t *vm, u_char *pc)

         if (code->ctor) {
             /* Array of the form [,,,], [1,,]. */
-            value = array->start;
-            length = array->length;
-
-            do {
-                njs_set_invalid(value);
-                value++;
-                length--;
-            } while (length != 0);
+            if (array->object.fast_array) {
+                value = array->start;
+                length = array->length;
+
+                do {
+                    njs_set_invalid(value);
+                    value++;
+                    length--;
+                } while (length != 0);
+            }

         } else {
             /* Array of the form [], [,,1], [1,2,3]. */
-            array->length = 0;
+            if (array->object.fast_array) {
+                array->length = 0;
+            }
         }

         njs_set_array(&vm->retval, array);
@@ -1272,27 +1276,63 @@ njs_vmcode_property_init(njs_vm_t *vm, njs_value_t *value, njs_value_t *key,
         index = (uint32_t) num;
         array = value->data.u.array;

-        if (index >= array->length) {
-            size = index - array->length;
+        if (array->object.fast_array) {
+            if (index >= array->length) {
+                size = index - array->length;
+
+                ret = njs_array_expand(vm, array, 0, size + 1);
+                if (njs_slow_path(ret != NJS_OK)) {
+                    return ret;
+                }
+
+                val = &array->start[array->length];
+
+                while (size != 0) {
+                    njs_set_invalid(val);
+                    val++;
+                    size--;
+                }
+
+                array->length = index + 1;
+            }
+
+            /* GC: retain. */
+            array->start[index] = *init;

-            ret = njs_array_expand(vm, array, 0, size + 1);
+        } else {
+            /* Slow array. */
+            ret = njs_value_to_key(vm, &name, key);
             if (njs_slow_path(ret != NJS_OK)) {
-                return ret;
+                return NJS_ERROR;
             }

-            val = &array->start[array->length];
+            njs_object_property_key_set(&lhq, &name, 0);
+            lhq.proto = &njs_object_hash_proto;
+            lhq.pool = vm->mem_pool;

-            while (size != 0) {
-                njs_set_invalid(val);
-                val++;
-                size--;
+            prop = njs_object_prop_alloc(vm, &name, init, 1);
+            if (njs_slow_path(prop == NULL)) {
+                return NJS_ERROR;
             }

-            array->length = index + 1;
-        }
+            lhq.value = prop;
+            lhq.replace = 1;

-        /* GC: retain. */
-        array->start[index] = *init;
+            ret = njs_lvlhsh_insert(njs_object_hash(value), &lhq);
+            if (njs_slow_path(ret != NJS_OK)) {
+                njs_internal_error(vm, "lvlhsh insert/replace failed");
+                return NJS_ERROR;
+            }
+
+            /* Update length if needed. */
+            if (index >= array->length) {
+                njs_set_array(&name, array);
+                ret = njs_array_length_redefine(vm, &name, index + 1);
+                if (njs_slow_path(ret != NJS_OK)) {
+                    return NJS_ERROR;
+                }
+            }
+        }

         break;

diff --git a/src/njs_string.c b/src/njs_string.c
index 83cede5..12214f8 100644
--- a/src/njs_string.c
+++ b/src/njs_string.c
@@ -3058,6 +3058,16 @@ njs_string_prototype_pad(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
     }

     if (pad_string.size > 1) {
+        /* Recompute pad_length for byte strings that might be UTF-8. */
+        if (pad_string.length == 0) {
+            ssize_t  utf8_len;
+
+            utf8_len = njs_utf8_length(pad_string.start, pad_string.size);
+            if (utf8_len >= 0) {
+                pad_length = utf8_len;
+            }
+        }
+
         n = padding / pad_length;
         trunc = padding % pad_length;

diff --git a/programs/escape.c b/programs/escape.c
index 8a90741..016d7be 100644
--- a/programs/escape.c
+++ b/programs/escape.c
@@ -28,17 +28,21 @@ htmlescape (const char *restrict src, const int cp)
 {
   int len;
   char *dest, *d;
-  unsigned char *s;
+  const unsigned char *s;
   if (!src)
     return NULL;
   len = strlen (src) + 10;
   d = malloc (len);
-  s = (unsigned char *)src;
+  s = (const unsigned char *)src;
   dest = d;
-  while (*s++)
+  while (*s)
     {
       const int off = d - dest;
-      if (off >= len - 8)
+      /* Check if we have enough space for the worst-case escape sequence.
+       * The longest escape is "&#xFF;" (6 chars) plus null terminator = 7 bytes.
+       * We need to check BEFORE writing, not after.
+       */
+      if (off >= len - 7)
         {
           len += 10;
           dest = realloc (dest, len);
@@ -46,23 +50,30 @@ htmlescape (const char *restrict src, const int cp)
         }
       switch (*s)
         {
-        case '"': strcat (d, "&quot;"); d += 6; break;
-        case '\'': strcat (d, "&#39;"); d += 5; break;
-        case '`': strcat (d, "&#96;"); d += 5; break;
-        case '&': strcat (d, "&amp;"); d += 5; break;
-        case '<': strcat (d, "&lt;"); d += 4; break;
-        case '>': strcat (d, "&gt;"); d += 4; break;
-        case '{': strcat (d, "&#123;"); d += 6; break;
-        case '}': strcat (d, "&#125;"); d += 6; break;
+        case '"': memcpy (d, "&quot;", 6); d += 6; break;
+        case '\'': memcpy (d, "&#39;", 5); d += 5; break;
+        case '`': memcpy (d, "&#96;", 5); d += 5; break;
+        case '&': memcpy (d, "&amp;", 5); d += 5; break;
+        case '<': memcpy (d, "&lt;", 4); d += 4; break;
+        case '>': memcpy (d, "&gt;", 4); d += 4; break;
+        case '{': memcpy (d, "&#123;", 6); d += 6; break;
+        case '}': memcpy (d, "&#125;", 6); d += 6; break;
         default:
           if (*s >= 127) // maybe encodings, no utf8 (see htmlwescape)
             {
-              sprintf (d, "&#x%X;", *s); // 4 + 4
-              d += strlen (d);
+              /* sprintf can write up to 7 bytes for &#xFF; (6 chars + null) */
+              if (off >= len - 7)
+                {
+                  len += 10;
+                  dest = realloc (dest, len);
+                  d = dest + off;
+                }
+              d += sprintf (d, "&#x%X;", *s);
             }
           else if (*s >= 20)
             *d++ = *s;
         }
+      s++;
     }
   *d = 0;
   return dest;
@@ -73,44 +84,57 @@ htmlwescape (BITCODE_TU wstr)
 {
   int len = 0;
   char *dest, *d;
-  BITCODE_TU tmp = wstr;
+  BITCODE_TU s;
   BITCODE_RS c;

   if (!wstr)
     return NULL;
-  while ((c = *tmp++))
+  s = wstr;
+  while ((c = *s++))
     len++;
   len += 16;
   d = dest = malloc (len);
+  s = wstr;

-  while (*wstr++)
+  while (*s)
     {
       const int off = d - dest;
-      if (off >= len - 8)
+      /* Check if we have enough space for the worst-case escape sequence.
+       * The longest escape is "&#xFF;" (6 chars) plus null terminator = 7 bytes.
+       * We need to check BEFORE writing, not after.
+       */
+      if (off >= len - 7)
         {
           len += 16;
           dest = realloc (dest, len);
           d = dest + off;
         }
-      switch (*wstr)
+      switch (*s)
         {
-        case 34: strcat (d, "&quot;"); d += 6; break;
-        case 39: strcat (d, "&#39;"); d += 5; break;
-        case 38: strcat (d, "&amp;"); d += 5; break;
-        case 60: strcat (d, "&lt;"); d += 4; break;
-        case 62: strcat (d, "&gt;"); d += 4; break;
-        case 96: strcat (d, "&#96;"); d += 5; break;
-        case 123: strcat (d, "&#123;"); d += 6; break;
-        case 125: strcat (d, "&#125;"); d += 6; break;
+        case 34: memcpy (d, "&quot;", 6); d += 6; break;
+        case 39: memcpy (d, "&#39;", 5); d += 5; break;
+        case 38: memcpy (d, "&amp;", 5); d += 5; break;
+        case 60: memcpy (d, "&lt;", 4); d += 4; break;
+

