diff --git a/src/njs_object.c b/src/njs_object.c
index ad03bc3..5815435 100644
--- a/src/njs_object.c
+++ b/src/njs_object.c
@@ -2113,6 +2113,24 @@ njs_object_set_prototype(njs_vm_t *vm, njs_object_t *object,
 {
     const njs_object_t *proto;

+    if (njs_slow_path(njs_is_null(value))) {
+        if (!object->extensible) {
+            return NJS_DECLINED;
+        }
+
+        object->__proto__ = NULL;
+        return NJS_OK;
+    }
+
+    if (njs_slow_path(!njs_is_object(value))) {
+        return NJS_DECLINED;
+    }
+
+    /* Validate that value->type is a valid object type */
+    if (njs_slow_path(value->type < NJS_OBJECT || value->type >= NJS_VALUE_TYPE_MAX)) {
+        return NJS_DECLINED;
+    }
+
     proto = njs_object(value);

     if (njs_slow_path(object->__proto__ == proto)) {
@@ -2158,12 +2176,21 @@ njs_object_prototype_proto(njs_vm_t *vm, njs_object_prop_t *prop,
     object = njs_object(value);

     if (setval != NULL) {
-        if (njs_is_object(setval) || njs_is_null(setval)) {
+        if (njs_is_null(setval)) {
             ret = njs_object_set_prototype(vm, object, setval);
             if (njs_slow_path(ret == NJS_ERROR)) {
                 njs_type_error(vm, "Cyclic __proto__ value");
                 return NJS_ERROR;
             }
+        } else if (njs_is_object(setval)) {
+            /* Validate that setval->type is a valid object type */
+            if (setval->type >= NJS_OBJECT && setval->type < NJS_VALUE_TYPE_MAX) {
+                ret = njs_object_set_prototype(vm, object, setval);
+                if (njs_slow_path(ret == NJS_ERROR)) {
+                    njs_type_error(vm, "Cyclic __proto__ value");
+                    return NJS_ERROR;
+                }
+            }
         }

         njs_set_undefined(retval);
