diff --git a/frontend/mp4read.c b/frontend/mp4read.c
index 1414684..acaba3f 100644
--- a/frontend/mp4read.c
+++ b/frontend/mp4read.c
@@ -337,13 +337,69 @@ static int stszin(int size)
 {
     int cnt;
     uint32_t ofs;
+    uint32_t sample_size;

     // version/flags
     u32in();
     // Sample size
-    u32in();
+    sample_size = u32in();
     // Number of entries
     mp4config.frame.ents = u32in();
+    
+    // Check minimum atom size
+    if (size < 12)
+        return ERR_FAIL;
+    
+    // Handle fixed sample size case
+    if (sample_size != 0)
+    {
+        // All samples have the same size, no entry table follows
+        // Atom size must be exactly 12 bytes for fixed sample size
+        if (size != 12)
+            return ERR_FAIL;
+        
+        // Check for overflow in total size calculation
+        if (mp4config.frame.ents > UINT32_MAX / sample_size)
+            return ERR_FAIL;
+        
+        // Allocate array for cumulative offsets (ents + 1 elements)
+        if (mp4config.frame.ents == UINT32_MAX)
+            return ERR_FAIL; // Overflow in ents + 1
+        
+        mp4config.frame.data = malloc(sizeof(*mp4config.frame.data)
+                                      * (mp4config.frame.ents + 1));
+        if (!mp4config.frame.data)
+            return ERR_FAIL;
+        
+        ofs = 0;
+        mp4config.frame.data[0] = ofs;
+        for (cnt = 0; cnt < mp4config.frame.ents; cnt++)
+        {
+            ofs += sample_size;
+            mp4config.frame.data[cnt + 1] = ofs;
+            
+            if (ofs < mp4config.frame.data[cnt])
+                return ERR_FAIL;
+        }
+        
+        if (mp4config.frame.maxsize < sample_size)
+            mp4config.frame.maxsize = sample_size;
+        
+        return size;
+    }
+    
+    // Variable sample size case: check atom has enough data for entry table
+    // Required size: 12 (header) + ents * 4 (entry table)
+    if (mp4config.frame.ents > (UINT32_MAX - 12) / 4)
+        return ERR_FAIL; // Integer overflow in size calculation
+    
+    if (12 + mp4config.frame.ents * 4 > (uint32_t)size)
+        return ERR_FAIL; // Atom too small for claimed number of entries
+    
+    // Check for overflow in allocation size calculation
+    if (mp4config.frame.ents == UINT32_MAX)
+        return ERR_FAIL; // Overflow in ents + 1
+    
     // fixme: check atom size
     mp4config.frame.data = malloc(sizeof(*mp4config.frame.data)
                                   * (mp4config.frame.ents + 1));

