+#include <stdio.h>
+#include <string.h>
+
+void test_edge_cases() {
+    printf("Testing edge cases:\n");
+    
+    // Test 1: position 2045
+    {
+        unsigned char pixels[2048];
+        unsigned char *q = pixels + 2045;
+        printf("Position 2045: (2045+3)=%d >= 2048? %s\n", 
+               2045+3, (2045+3) >= 2048 ? "flush" : "write");
+        // Should flush
+    }
+    
+    // Test 2: position 2046  
+    {
+        unsigned char pixels[2048];
+        unsigned char *q = pixels + 2046;
+        printf("Position 2046: (2046+3)=%d >= 2048? %s\n",
+               2046+3, (2046+3) >= 2048 ? "flush" : "write");
+        // Should flush
+    }
+    
+    // Test 3: position 2047
+    {
+        unsigned char pixels[2048];
+        unsigned char *q = pixels + 2047;
+        printf("Position 2047: (2047+3)=%d >= 2048? %s\n",
+               2047+3, (2047+3) >= 2048 ? "flush" : "write");
+        // Should flush
+    }
+    
+    // Test 4: position 0
+    {
+        unsigned char pixels[2048];
+        unsigned char *q = pixels;
+        printf("Position 0: (0+3)=%d >= 2048? %s\n",
+               0+3, (0+3) >= 2048 ? "flush" : "write");
+        // Should write
+    }
+    
+    // Test 5: position 2044
+    {
+        unsigned char pixels[2048];
+        unsigned char *q = pixels + 2044;
+        printf("Position 2044: (2044+3)=%d >= 2048? %s\n",
+               2044+3, (2044+3) >= 2048 ? "flush" : "write");
+        // 2047 < 2048, should write
+    }
+}
+
+int main() {
+    test_edge_cases();
+    return 0;
+}
diff --git a/test_pnm_fix.c b/test_pnm_fix.c
new file mode 100644
index 0000000..ca816fd
--- /dev/null
+++ b/test_pnm_fix.c
@@ -0,0 +1,38 @@
+#include <stdio.h>
+#include <string.h>
+
+// Simulate the fixed logic
+void test_fix() {
+    unsigned char pixels[2048];
+    unsigned char *q = pixels;
+    ssize_t i;
+    
+    // Test: fill buffer almost full
+    for (i = 0; i < 1023; i++) {  // 1023 * 2 = 2046 bytes
+        // Simulate writing digit and space
+        *q++ = '0';
+        *q++ = ' ';
+    }
+    // Now q-pixels = 2046
+    
+    // Next pixel would cause overflow in original code
+    // With fix: check (2046+3) >= 2048 -> true, flush
+    printf("Buffer position before check: %ld\n", q - pixels);
+    printf("Check (q-pixels+3) >= 2048: %s\n", 
+           (q - pixels + 3) >= 2048 ? "true (flush)" : "false (write)");
+    
+    // After flush, q reset to pixels
+    q = pixels;
+    
+    // Write digit and space
+    *q++ = '0';
+    *q++ = ' ';
+    
+    printf("Buffer position after writing: %ld\n", q - pixels);
+    printf("Test passed - no overflow\n");
+}
+
+int main() {
+    test_fix();
+    return 0;
+}

