+#include <stdio.h>
+#include <string.h>
+
+// Simulate the fixed function
+static char initialLogFileName[256] = "";
+
+void test_lou_logFile(const char *fileName) {
+    if (fileName == NULL || fileName[0] == 0) return;
+    if (initialLogFileName[0] == 0) {
+        size_t len = strlen(fileName);
+        if (len < sizeof(initialLogFileName)) {
+            strcpy(initialLogFileName, fileName);
+            printf("Copied filename (len=%zu): %s\n", len, initialLogFileName);
+        } else {
+            /* File name too long, don't copy it */
+            initialLogFileName[0] = '\0';
+            printf("Filename too long (len=%zu), not copied\n", len);
+        }
+    }
+}
+
+int main() {
+    // Test 1: Short filename (should copy)
+    char short_name[100] = "short.txt";
+    test_lou_logFile(short_name);
+    
+    // Test 2: Exactly 255 character filename (should copy)
+    char exact_name[257];
+    memset(exact_name, 'a', 255);
+    exact_name[255] = '\0';
+    test_lou_logFile(exact_name);
+    
+    // Reset for test
+    initialLogFileName[0] = '\0';
+    
+    // Test 3: Exactly 256 character filename (should NOT copy)
+    char long_name[257];
+    memset(long_name, 'b', 256);
+    long_name[256] = '\0';
+    test_lou_logFile(long_name);
+    
+    // Test 4: Very long filename (should NOT copy)
+    char very_long[5000];
+    memset(very_long, 'c', 4096);
+    very_long[4096] = '\0';
