+++ b/test_fix2.c
@@ -0,0 +1,45 @@
+#include <stdio.h>
+#include <string.h>
+#include <stdlib.h>
+
+// Simulate the fixed function
+static char initialLogFileName[256] = "";
+
+void test_lou_logFile(const char *fileName) {
+    if (fileName == NULL || fileName[0] == 0) return;
+    if (initialLogFileName[0] == 0) {
+        size_t len = strlen(fileName);
+        printf("Checking filename length: %zu, buffer size: %zu\n", len, sizeof(initialLogFileName));
+        if (len < sizeof(initialLogFileName)) {
+            strcpy(initialLogFileName, fileName);
+            printf("Copied filename (len=%zu, fits: %zu < %zu)\n", len, len, sizeof(initialLogFileName));
+        } else {
+            /* File name too long, don't copy it */
+            initialLogFileName[0] = '\0';
+            printf("Filename too long (len=%zu, doesn't fit: %zu >= %zu), not copied\n", len, len, sizeof(initialLogFileName));
+        }
+    }
+}
+
+int main() {
+    // Test: Exactly 255 character filename (should copy)
+    char *exact_name = malloc(256);
+    memset(exact_name, 'a', 255);
+    exact_name[255] = '\0';
+    printf("String length: %zu\n", strlen(exact_name));
+    test_lou_logFile(exact_name);
+    free(exact_name);
+    
+    // Reset for test
+    initialLogFileName[0] = '\0';
+    
+    // Test: Exactly 256 character filename (should NOT copy)
+    char *long_name = malloc(257);
+    memset(long_name, 'b', 256);
+    long_name[256] = '\0';
+    printf("\nString length: %zu\n", strlen(long_name));
+    test_lou_logFile(long_name);
+    free(long_name);
+

