+#include <stdio.h>
+#include <stdlib.h>
+#include <string.h>
+#include <stdint.h>
+
+// Simulate the fixed logic
+void test_fix() {
+    // Test case from crash: mha_config_size=3, dsi_size=17, dsi_size-5=12
+    unsigned char dsi[17] = {0};
+    dsi[3] = 0;  // mha_config_size high byte
+    dsi[4] = 3;  // mha_config_size low byte = 3
+    
+    uint32_t dsi_size = 17;
+    uint32_t mha_config_size = (dsi[3] << 8) | dsi[4];
+    
+    printf("Test case: mha_config_size=%u, dsi_size=%u, dsi_size-5=%u\n", 
+           mha_config_size, dsi_size, dsi_size-5);
+    
+    // Original code would allocate 3 bytes, copy 12 bytes -> OVERFLOW
+    // Fixed code checks: mha_config_size > dsi_size - 5?
+    if (mha_config_size > dsi_size - 5) {
+        printf("ERROR: mha_config_size %u exceeds available data %u\n", 
+               mha_config_size, dsi_size - 5);
+        // Would return GF_BAD_PARAM
+    } else {
+        printf("OK: mha_config_size %u <= available data %u\n",
+               mha_config_size, dsi_size - 5);
+        // Allocate mha_config_size bytes, copy mha_config_size bytes
+        printf("Would allocate %u bytes, copy %u bytes\n", 
+               mha_config_size, mha_config_size);
+    }
+}
+
+int main() {
+    test_fix();
+    return 0;
+}

